# pylint: disable=missing-docstring
import sys
from dataclasses import dataclass
from typing import Iterator, TypeVar

try:
    from typing import Protocol, runtime_checkable, Annotated, Literal
except Exception:
    from typing_extensions import Protocol, runtime_checkable, Annotated, Literal  # type: ignore

if sys.version_info >= (3, 10):
    from types import EllipsisType

    KW_ONLY = {"kw_only": True}
    SLOTS = {"slots": True}
else:
    EllipsisType = type(Ellipsis)
    KW_ONLY = {}
    SLOTS = {}

__all__ = (
    "BaseMetadata",
    "GroupedMetadata",
    "Gt",
    "Ge",
    "Lt",
    "Le",
    "Interval",
    "MultipleOf",
    "MinLen",
    "MaxLen",
    "Len",
    "Timezone",
    "Predicate",
    "LowerCase",
    "UpperCase",
    "IsDigits",
    "IsFinite",
    "IsNotFinite",
    "IsNan",
    "IsNotNan",
    "IsInfinite",
    "IsNotInfinite",
    "doc",
    "DocInfo",
    "__version__",
)

__version__ = "0.7.0"

T = TypeVar("T")


class SupportsGt(Protocol[T]):
    def __gt__(self: T, __other: T) -> bool:
        ...


class SupportsGe(Protocol[T]):
    def __ge__(self: T, __other: T) -> bool:
        ...


class SupportsLt(Protocol[T]):
    def __lt__(self: T, __other: T) -> bool:
        ...


class SupportsLe(Protocol[T]):
    def __le__(self: T, __other: T) -> bool:
        ...


class SupportsMod(Protocol[T]):
    def __mod__(self: T, __other: T) -> T:
        ...


class BaseMetadata:
    __slots__ = ()


@dataclass(frozen=True, **SLOTS)
class Gt(BaseMetadata):
    gt: SupportsGt


@dataclass(frozen=True, **SLOTS)
class Ge(BaseMetadata):
    ge: SupportsGe


@dataclass(frozen=True, **SLOTS)
class Lt(BaseMetadata):
    lt: SupportsLt


@dataclass(frozen=True, **SLOTS)
class Le(BaseMetadata):
    le: SupportsLe


@runtime_checkable
class GroupedMetadata(Protocol):
    def __iter__(self) -> Iterator[BaseMetadata]:
        ...